import{_ as t,o,c as r,ag as a}from"./chunks/framework.1N8rnUr9.js";const h=JSON.parse('{"title":"Requirements","description":"","frontmatter":{},"headers":[],"relativePath":"guide/requirements.md","filePath":"guide/requirements.md","lastUpdated":1775715475000}'),n={name:"guide/requirements.md"};function i(s,e,d,l,m,u){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h1><p>Before installing TubeBay, make sure your environment meets the following requirements.</p><h2 id="system-requirements" tabindex="-1">System Requirements <a class="header-anchor" href="#system-requirements" aria-label="Permalink to &quot;System Requirements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Minimum Version</th><th>Recommended</th></tr></thead><tbody><tr><td><strong>WordPress</strong></td><td>5.8+</td><td>Latest stable</td></tr><tr><td><strong>WooCommerce</strong></td><td>6.0+</td><td>Latest stable</td></tr><tr><td><strong>PHP</strong></td><td>7.4+</td><td>8.0+</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WooCommerce Required</p><p>TubeBay is a WooCommerce extension. It <strong>will not activate</strong> without WooCommerce installed and active.</p></div><h2 id="connection-requirements" tabindex="-1">Connection Requirements <a class="header-anchor" href="#connection-requirements" aria-label="Permalink to &quot;Connection Requirements&quot;">​</a></h2><p>To sync videos from YouTube, you will need one of the following:</p><ol><li><strong>Google Account:</strong> For secure OAuth 2.0 connection (highest recommendation).</li><li><strong>YouTube Data API Key:</strong> For manual connection if you prefer to use your own Google Cloud projects.</li></ol><h2 id="browser-compatibility" tabindex="-1">Browser Compatibility <a class="header-anchor" href="#browser-compatibility" aria-label="Permalink to &quot;Browser Compatibility&quot;">​</a></h2><h3 id="admin-dashboard" tabindex="-1">Admin Dashboard <a class="header-anchor" href="#admin-dashboard" aria-label="Permalink to &quot;Admin Dashboard&quot;">​</a></h3><p>The React-based admin dashboard works best in modern evergreen browsers:</p><ul><li>Chrome / Edge (latest)</li><li>Firefox (latest)</li><li>Safari (latest)</li></ul><h3 id="frontend-video-player" tabindex="-1">Frontend Video Player <a class="header-anchor" href="#frontend-video-player" aria-label="Permalink to &quot;Frontend Video Player&quot;">​</a></h3><p>The embedded video players are powered by the official YouTube IFrame API. They are fully responsive and work in all modern desktop and mobile browsers.</p><h2 id="hosting-ssl" tabindex="-1">Hosting &amp; SSL <a class="header-anchor" href="#hosting-ssl" aria-label="Permalink to &quot;Hosting &amp; SSL&quot;">​</a></h2><ul><li><strong>SSL Certificate:</strong> Highly recommended (and required for some OAuth flows) to ensure secure communication between your site and Google APIs.</li><li><strong>Outbound Requests:</strong> Your server must be able to make outbound HTTPS requests to <code>google.com</code> and <code>googleapis.com</code>.</li></ul>',16)])])}const b=t(n,[["render",i]]);export{h as __pageData,b as default};
